def file_name_check(file_name):

    if not isinstance(file_name, str):

        return 'No'


    # Check for more than three digits

    if re.search(r'[0-9]{4,}', file_name):

        return 'No'


    # Check for one dot and non-empty substring before dot

    if '.' not in file_name or not file_name.split('.')[0]:

        return 'No'


    # Check that the substring before dot is a letter

    if not file_name.split('.')[0].isalpha():

        return 'No'


    # Check for allowed substring after dot

    if file_name.split('.')[-1] not in ['txt', 'exe', 'dll']:

        return 'No'


    return 'Yes'

